import{_ as e,o as a,c as i,a2 as t}from"./chunks/framework.DYQ4mM3C.js";const k=JSON.parse('{"title":"EnvVault","description":"","frontmatter":{},"headers":[],"relativePath":"index.md","filePath":"index.md","lastUpdated":1783311890000}'),l={name:"index.md"};function n(p,s,h,o,r,d){return a(),i("div",null,[...s[0]||(s[0]=[t(`<h1 id="envvault" tabindex="-1">EnvVault <a class="header-anchor" href="#envvault" aria-label="Permalink to &quot;EnvVault&quot;">​</a></h1><p>Keep real secrets out of project <code>.env</code> files and coding-agent prompts.</p><p>EnvVault replaces plaintext <code>.env</code> secrets with repository-safe <code>envvault://</code> references. At runtime, it resolves credentials from the OS credential store or starts a localhost proxy that gives the app a local URL and local proxy token.</p><h2 id="quick-start" tabindex="-1">Quick Start <a class="header-anchor" href="#quick-start" aria-label="Permalink to &quot;Quick Start&quot;">​</a></h2><p>Install EnvVault from the Homebrew tap:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">brew</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> trknhr/tap/envvault</span></span></code></pre></div><p>Register a credential once. Use the Admin UI for interactive setup:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">envvault</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> admin</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> start</span></span></code></pre></div><p>The printed localhost URL opens forms for adding credentials and creating optional proxies. Stored credential values are not displayed by the UI.</p><p>For a shorter interactive CLI path, use <code>set</code>. It reads the value from a hidden terminal prompt:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">envvault</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> credential</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> set</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> app/dev</span></span></code></pre></div><p>For scripts or repeatable tests, use the same command with explicit stdin:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">printf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;secret-value\\n&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> envvault</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> credential</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> set</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> app/dev</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --value-stdin</span></span></code></pre></div><p>Remove an unused credential with <code>envvault credential delete app/dev</code>. If profiles still reference it, deletion fails unless <code>--cascade</code> is supplied to remove those dependent profiles too.</p><p>Use a repository-safe reference in the app&#39;s <code>.env</code> file or pass the same reference with <code>envvault exec --env</code>:</p><div class="language-dotenv vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">dotenv</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">APP_SECRET</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">envvault://app/dev</span></span></code></pre></div><p>Launch the app through EnvVault:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">envvault</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> exec</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --env</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> APP_SECRET=envvault://app/dev</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> start</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">envvault</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> exec</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --env-file</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> .env</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> start</span></span></code></pre></div><p>For a tool that always reads a file under its home directory, inject a resolved copy of a repository-safe JSON, YAML, or TOML source into an isolated temporary home. For example, keep this non-secret file at <code>config/hogehoge.yaml</code>:</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">token</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">envvault://app/dev</span></span></code></pre></div><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">envvault</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> exec</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --home-file</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> .hogehoge=config/hogehoge.yaml</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> your-command</span></span></code></pre></div><p>The destination is relative to the isolated home. Relative source paths are resolved from the invocation working directory, and absolute source paths are also allowed.</p><h2 id="credential-flows" tabindex="-1">Credential Flows <a class="header-anchor" href="#credential-flows" aria-label="Permalink to &quot;Credential Flows&quot;">​</a></h2><ul><li><strong>Direct credential</strong>: use <code>envvault://&lt;credential&gt;</code> for the default local development path. The child process receives the real value in its environment.</li><li><strong>Isolated home file</strong>: use repeatable <code>--home-file DEST=SOURCE</code> for a tool that requires a home-directory file. EnvVault resolves whole-string direct credential references in source values, leaves the source unchanged, and removes the isolated copy after the child exits normally. JSON, YAML, and TOML sources are supported.</li><li><strong>Proxy</strong>: use generated <code>envvault://&lt;proxy&gt;/base-url</code> and <code>envvault://&lt;proxy&gt;/token</code> references when an app accepts a custom endpoint and bearer token.</li><li><strong>Local state</strong>: store only credential names and proxy policy in config; store real credential values in the OS credential store.</li></ul><h2 id="agent-skill" tabindex="-1">Agent Skill <a class="header-anchor" href="#agent-skill" aria-label="Permalink to &quot;Agent Skill&quot;">​</a></h2><p>Install the EnvVault skill with the <code>skills</code> CLI:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> skills</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> trknhr/envvault</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --skill</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> envvault</span></span></code></pre></div><p>From a local checkout:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> skills</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> .</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --skill</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> envvault</span></span></code></pre></div><p>Use the <code>skills</code> CLI options to choose global/project scope or a specific agent, for example <code>-g</code> for global installation or <code>-a &lt;agent&gt;</code>. Restart your agent after installing or updating skills.</p><h2 id="advanced-api-proxy" tabindex="-1">Advanced API Proxy <a class="header-anchor" href="#advanced-api-proxy" aria-label="Permalink to &quot;Advanced API Proxy&quot;">​</a></h2><p>The <a href="/envvault/examples.html">proxy examples</a> show the optional proxy workflow: a credential stays in the OS credential store while the app receives only a localhost proxy URL and local token.</p>`,32)])])}const g=e(l,[["render",n]]);export{k as __pageData,g as default};
